const tz = 'America/Bogota';
const now = new Date();
const fmt = new Intl.DateTimeFormat('en-CA', {
  timeZone: tz, year:'numeric', month:'2-digit', day:'2-digit',
  hour:'2-digit', minute:'2-digit', second:'2-digit', hour12:false
}).formatToParts(now);
const g = (t) => fmt.find(p => p.type === t).value;
const yyyy = g('year'), mm = g('month'), dd = g('day');
const input = $json.body || {};
const ts_id = input.ts_id;
const ts_name = input.ts_name || `${yyyy}-${mm}-${dd}`;
const scriptResults = input.scriptResults || {};
return [{ json: {
  ts_id, ts_name, scriptResults, yyyy, mm, dd,
  gh_path: `${yyyy}/${mm}/${yyyy}-${mm}-${dd}`,
  outputs_src: '1qulBT2VmQn1XL6cK1kednqiTSWzcO0Dq',
  input_folders: [
    '12zjruSVCy7ZSP6XrcToed2N0NKfx6L6c',
    '17Ut-5dL7ci9RZZhX72iD8qejZZdKnNkh',
    '177YEDw4l3-RD7Vg7rG9-ApGyey7Kh3tn',
    '1KZt98PYd9V6w_zfSpl-fOl6F1v56Vb4t',
    '12jatMOkDTNHzIwwPZOlHnWc33uoqcxwM',
      '1nd2P5MG-eTDPHpeTzWIqlJpzo6k8rap6',
  ],
} }];

const files = $json.files || [];
const seen = {};
for (const f of files) {
  if (f.name.startsWith('paso1_') && !seen.paso1) seen.paso1 = f;
  else if (f.name.startsWith('paso2_')) {
    const isV = /valles|lirio/i.test(f.name);
    const k = isV ? 'paso2_valles' : 'paso2_credil';
    if (!seen[k]) seen[k] = f;
  }
  else if (f.name.startsWith('paso3_') && !seen.paso3) seen.paso3 = f;
}
const outputsTargetId = $('Create OUTPUTS subfolder').first().json.id;
const out = [];
for (const [key, f] of Object.entries(seen)) {
  out.push({ json: { key, sourceId: f.id, sourceName: f.name, targetId: outputsTargetId } });
}
if (out.length === 0) return [{ json: { _empty: true, targetId: outputsTargetId } }];
return out;

// NO BORRAR SI FALLA (2026-05-31): si algun script fallo, NO borrar los inputs.
// Se apunta a una carpeta inexistente para que el flujo siga (NOOP) sin borrar nada real.
const setup = $('Setup POST').first().json;
const sr = setup.scriptResults || {};
const s3 = sr.script3 || {};
const huboError = (s3.script1_status==='error' || s3.script2_status==='error' || s3.script3_status==='error'
  || (sr.script1 && sr.script1.script1_status==='error')
  || (sr.script2 && sr.script2.script2_status==='error'));
if (huboError) {
  return [{ json: { srcId: 'NO_BORRAR_POR_ERROR', _skip_delete: true } }];
}
return (setup.input_folders || []).map(srcId => ({ json: { srcId } }));

const items = $input.all();
const out = [];
for (const it of items) {
  const files = it.json.files || [];
  for (const f of files) {
    if (f.mimeType === 'application/vnd.google-apps.folder') continue;
    out.push({ json: { fileId: f.id, fileName: f.name } });
  }
}
if (out.length === 0) return [{ json: { _empty: true, fileId: 'NOOP' } }];
return out;

const setup = $('Setup POST').first().json;
const copies = $('Copy paso outputs').all().map(i => i.json).filter(j => !j._empty);
const deletes = $('Delete input files').all().map(i => i.json).filter(j => !j._empty);
const sr = setup.scriptResults || {};

// El script3 acumula todos los status previos.
const s3obj = sr.script3 || {};
const s1 = s3obj.script1_status || sr.script1?.script1_status || 'desconocido';
const s2 = s3obj.script2_status || sr.script2?.script2_status || 'desconocido';
const s3 = s3obj.script3_status || 'desconocido';

const errores = [];
if (s1 === 'error') errores.push(`Script 1 (Recargas): ${s3obj.script1_error || sr.script1?.script1_error || 'fallo sin detalle'}`);
if (s2 === 'error') errores.push(`Script 2 (Bancos): ${s3obj.script2_error || sr.script2?.script2_error || 'fallo sin detalle'}`);
if (s3 === 'error') errores.push(`Script 3 (Conciliacion): ${s3obj.script3_error || 'fallo sin detalle'}`);

const hayError = errores.length > 0;
const estadoTxt = hayError ? '❌ ERROR' : '✅ OK';
const statusJson = hayError ? 'ERROR' : 'OK';

let md = `# Reporte de Procesamiento — ${setup.yyyy}-${setup.mm}-${setup.dd}\n\n`;
md += `**Fecha y hora (Bogota):** ${setup.ts_name.replace('_', ' ')}\n\n`;
md += `**Estado:** ${estadoTxt}\n\n`;
md += `**Carpeta historial:** \`${setup.ts_name}\`\n\n`;

if (hayError) {
  md += `## ⚠️ Errores detectados\n\n`;
  for (const e of errores) md += `- ${e}\n`;
  md += `\n`;
  md += `**Estado de los scripts:** Script1=${s1}, Script2=${s2}, Script3=${s3}\n\n`;
  md += `> ⚠️ Los archivos de input **NO se borraron** (quedan en sus carpetas para que corrijas y vuelvas a procesar). Revisá el archivo del script que falló y reprocesá.\n\n`;
}

md += `## Resumen\n\n`;
md += `- Outputs copiados al historial: **${copies.length}**\n`;
md += `- Archivos eliminados de input: **${deletes.length}**\n\n`;

if (copies.length > 0) {
  md += `## Outputs generados\n\n`;
  for (const c of copies) md += `- \`${c.name}\`\n`;
  md += `\n`;
}

if (Object.keys(sr).length > 0) {
  md += `## Detalle tecnico de Scripts\n\n`;
  md += '```json\n' + JSON.stringify(sr, null, 2) + '\n```\n\n';
}
md += `---\n_Generado por Conciliacion_HISTORIAL_POST_\n`;

const logJson = {
  timestamp: setup.ts_name,
  date: `${setup.yyyy}-${setup.mm}-${setup.dd}`,
  status: statusJson,
  errores: errores,
  scriptStatus: { script1: s1, script2: s2, script3: s3 },
  ts_id: setup.ts_id,
  copiedCount: copies.length,
  copies: copies.map(c => ({ name: c.name, id: c.id })),
  deletedCount: deletes.length,
  scriptResults: sr,
};

return [{ json: {
  reporteMd: md,
  reporteB64: Buffer.from(md, 'utf-8').toString('base64'),
  logJson: JSON.stringify(logJson, null, 2),
  logB64: Buffer.from(JSON.stringify(logJson, null, 2), 'utf-8').toString('base64'),
  ghReportePath: `${setup.gh_path}/reporte.md`,
  ghLogPath: `${setup.gh_path}/log.json`,
  ts_name: setup.ts_name,
  date: `${setup.yyyy}-${setup.mm}-${setup.dd}`,
  status: statusJson,
}}];

const setup = $('Setup POST').first().json;
const ghR = $('GH PUT reporte').first().json;
const ghL = $('GH PUT log').first().json;
return [{ json: {
  ts_name: setup.ts_name, ts_id: setup.ts_id,
  copiedCount: $('Copy paso outputs').all().filter(i => !i.json._empty).length,
  deletedCount: $('Delete input files').all().filter(i => !i.json._empty).length,
  github: {
    reporteCommit: ghR.commit?.sha?.slice(0,10) || null, reporteUrl: ghR.content?.html_url || null,
    logCommit: ghL.commit?.sha?.slice(0,10) || null, logUrl: ghL.content?.html_url || null,
  },
}}];

const su = $('Setup POST').first().json;
const outId = $('Create OUTPUTS subfolder').first().json.id;
let paso3Id = null;
for (const it of $('Copy paso outputs').all()) { const j = it.json||{}; if (String(j.name||'').startsWith('paso3_')) { paso3Id = j.id; break; } }
const puntero = { fecha_proceso: su.ts_name, historial_id: su.ts_id, outputs_id: outId, paso3_id: paso3Id, mapeo_id: '1lx9lNn17jj7KxJ3O3GYWZduMxHKQ8EI4' };
return [{ json: { puntero } }];
